      "path": "src/modules/comments/service.js",
      "content": "const { randomUUID } = require('node:crypto');
const { getProject, getTask } = require('../projects/service');
const { sendError } = require('../../lib/errors');

const createComment = async (projectId, taskId, { message }) => {
  const project = await getProject(projectId);
  if (!project) {
    throw sendError(null, 404, 'NOT_FOUND', 'Project not found');
  }

  const task = await getTask(projectId, taskId);
  if (!task) {
    throw sendError(null, 404, 'NOT_FOUND', 'Task not found');
  }

  if (!message) {
    throw sendError(null, 400, 'BAD_REQUEST', 'Message is required');
  }

  const comment = {
    id: randomUUID(),
    projectId,
    taskId,
    message,
    createdAt: new Date()
  };

  // Save comment to database
  return comment;
};

module.exports = { createComment };"
